const text = $input.first().json.organized_text;
const categoriesRaw = $input.first().json.categories;

// 1️⃣ Transformar string "A | B | C" em array
const categories = categoriesRaw
  .split('|')
  .map(c => c.trim())
  .filter(Boolean);

// 2️⃣ Função para escapar caracteres especiais de regex
function escapeRegex(text) {
  return text.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

// 3️⃣ Criar regex dinâmico baseado nas categorias
const sectionRegex = new RegExp(
  `(${categories.map(escapeRegex).join('|')})`,
  'gi'
);

// 4️⃣ Fazer split usando o regex dinâmico
const parts = text.split(sectionRegex);

const chunks = [];

for (let i = 1; i < parts.length; i += 2) {
  const title = parts[i].trim();
  let content = parts[i + 1]?.trim();

  if (content) {
    chunks.push({
      category: title,
      content: `${title}\n${content}`
    });
  }
}

return chunks.map(c => ({ json: c }));

const rawText = $input.first().json.content.parts[0].text

// Remove ```json e ```
const cleaned = rawText
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .trim();

// Converte string em JSON
const parsed = JSON.parse(cleaned);

return [
  {
    json: parsed
  }
];
